#[test]
fn minimum_should_match_narrows_the_matched_set_even_with_must_present() {
    // cat={0,2}, dog={0,1}, bird={1,4} (all real `PostingsEnum`-derived, from
    // `manifest.properties`, not hand-picked). must=[cat] alone gives {0,2}; adding
    // should=[dog,bird] with minimum_should_match=1 additionally requires at least
    // one of dog/bird -- doc 2 satisfies neither, so it drops out even though it
    // satisfies `must`, unlike the `minimum_should_match == 0` case
    // (`must_with_should_present_ignores_should_for_matching`, above) where doc 2
    // stays. This is the exact real-`BooleanWeight` interaction rule this task
    // implements: `should` gates matching regardless of `must`'s presence, once
    // `minimum_should_match > 0`.
    let (fields, doc, id, suffix, m) = open_segment();
    let doc_in = DocInput::open(&doc, &id, &suffix).expect("open .doc");

    let cat = m.doc_set("body", "cat");
    let dog = m.doc_set("body", "dog");
    let bird = m.doc_set("body", "bird");
    assert_eq!(cat, BTreeSet::from([0, 2]), "fixture sanity");
    let expected: BTreeSet<i32> = cat
        .iter()
        .copied()
        .filter(|d| dog.contains(d) || bird.contains(d))
        .collect();
    assert_eq!(expected, BTreeSet::from([0]), "fixture sanity");

    let mut collector = VecCollector::default();
    let query = BooleanQuery::new()
        .with_must([TermQuery::new("body", "cat")])
        .with_should([
            TermQuery::new("body", "dog"),
            TermQuery::new("body", "bird"),
        ])
        .with_minimum_should_match(1);
    search_boolean_query(
        &fields,
        Some(&doc_in),
        None,
        None,
        None,
        None,
        &query,
        &mut collector,
    )
    .unwrap();
    assert_eq!(collector.docs, sorted_vec(expected));
}

#[test]
fn must_across_multi_block_and_singleton_fields() {
    // Combines the multi-doc-block "big" field (docFreq 300) with the
    // singleton-in-term-dictionary "id" field to exercise the conjunction merge
    // across two structurally different postings representations. "big"'s
    // "everywhere" term covers docs 5..=304; "id2" is doc 2 alone, so they never
    // overlap.
    let (fields, doc, id, suffix, m) = open_segment();
    let doc_in = DocInput::open(&doc, &id, &suffix).expect("open .doc");

    let expected: BTreeSet<i32> = m
        .doc_set("big", "everywhere")
        .intersection(&m.doc_set("id", "id2"))
        .copied()
        .collect();
    assert!(expected.is_empty(), "fixture sanity: disjoint doc sets");

    let mut collector = VecCollector::default();
    let query = BooleanQuery::new().with_must([
        TermQuery::new("big", "everywhere"),
        TermQuery::new("id", "id2"),
    ]);
    search_boolean_query(
        &fields,
        Some(&doc_in),
        None,
        None,
        None,
        None,
        &query,
        &mut collector,
    )
    .unwrap();
    assert!(collector.docs.is_empty());
}

/// Task #25 (nested `BooleanQuery` clauses): a top-level `must` clause that is
/// itself a nested `BooleanQuery`, against this fixture's real `body` postings --
/// proves `resolve_clause_docs`/`matched_boolean_docs`'s recursion produces the
/// same result real Lucene's own `BooleanQuery.add(nestedQuery, Occur.MUST)` would,
/// computed here from the same real `PostingsEnum`-derived doc sets the flat
/// boolean tests above already use (not hand-picked doc IDs).
#[test]
fn nested_boolean_must_clause_matches_real_lucene_intersection_of_the_nested_disjunction() {
    let (fields, doc, id, suffix, m) = open_segment();
    let doc_in = DocInput::open(&doc, &id, &suffix).expect("open .doc");

    let cat = m.doc_set("body", "cat");
    let dog = m.doc_set("body", "dog");
    let bird = m.doc_set("body", "bird");
    // Nested query: should=[cat, bird] -- its own disjunction, cat ∪ bird.
    let nested_expected: BTreeSet<i32> = cat.union(&bird).copied().collect();
    assert_eq!(
        nested_expected,
        BTreeSet::from([0, 1, 2, 4]),
        "fixture sanity"
    );
    // Top level: must=[dog, nested] -- dog's doc set intersected with the nested
    // query's own disjunction.
    let expected: BTreeSet<i32> = dog.intersection(&nested_expected).copied().collect();
    assert_eq!(expected, BTreeSet::from([0, 1]), "fixture sanity");

    let mut collector = VecCollector::default();
    let nested = BooleanQuery::new().with_should([
        TermQuery::new("body", "cat"),
        TermQuery::new("body", "bird"),
    ]);
    let query = BooleanQuery::new().with_must([
        Clause::Term(TermQuery::new("body", "dog")),
        Clause::Boolean(Box::new(nested)),
    ]);
    search_boolean_query(
        &fields,
        Some(&doc_in),
        None,
        None,
        None,
        None,
        &query,
        &mut collector,
    )
    .unwrap();
    assert_eq!(collector.docs, sorted_vec(expected));
}

/// `BooleanQuery::rewrite`'s single-clause-unwrap rule, proven end-to-end: the
/// same `must=[cat]`-alone query, scored via `search_boolean_query_scored`,
/// produces byte-identical (doc ID *and* score) results before and after
/// `rewrite()` collapses it to a bare `Clause::Term`. This is the critical
/// correctness property the rewrite pass promises -- not just "the shape looks
/// simplified", but that a real caller swapping in the rewritten query gets
/// the exact same ranked results against a real segment.
#[test]
fn rewrite_produces_identical_scored_results_for_single_must_clause() {
    let (fields, doc, id, suffix, _m) = open_segment();
    let doc_in = DocInput::open(&doc, &id, &suffix).expect("open .doc");

    let query = BooleanQuery::new().with_must([TermQuery::new("body", "cat")]);
    let rewritten_clause = query.clone().rewrite();
    // Sanity: the rewrite actually collapsed to the bare leaf term, not a no-op.
    assert_eq!(
        rewritten_clause,
        Clause::Term(TermQuery::new("body", "cat"))
    );
    let rewritten_query = BooleanQuery::new().with_must([rewritten_clause]);

    let mut before = lucene_search::collector::TopDocsCollector::new(100);
    search_boolean_query_scored(
        &fields,
        Some(&doc_in),
        None,
        None,
        None,
        None,
        &query,
        None,
        &mut before,
    )
    .unwrap();

    let mut after = lucene_search::collector::TopDocsCollector::new(100);
    search_boolean_query_scored(
        &fields,
        Some(&doc_in),
        None,
        None,
        None,
        None,
        &rewritten_query,
        None,
        &mut after,
    )
    .unwrap();

    assert!(!before.top_docs().is_empty(), "fixture sanity: some hits");
    assert_eq!(before.top_docs(), after.top_docs());
}

